<?php
namespace App\Services;
use App\Mail\CertificateIssuedMail; use App\Models\Certificate; use App\Models\Donation; use Barryvdh\DomPDF\Facade\Pdf; use Illuminate\Support\Facades\Mail; use Illuminate\Support\Facades\Storage; use Illuminate\Support\Str;
class CertificateService { public function issue(Donation $donation): Certificate { abort_unless($donation->status === 'verified', 422, 'Sertifikat hanya untuk donasi terverifikasi.'); if ($donation->certificate) return $donation->certificate; $number='SP-'.now()->format('Ymd').'-'.Str::upper(Str::random(6)); $pdf=Pdf::loadView('pdf.certificate',['donation'=>$donation->load('campaign'),'number'=>$number])->setPaper('a4','landscape'); $path="certificates/{$number}.pdf"; Storage::disk('public')->put($path, $pdf->output()); return Certificate::create(['donation_id'=>$donation->id,'certificate_number'=>$number,'pdf_path'=>$path,'issued_at'=>now()]); } public function email(Certificate $certificate): void { Mail::to($certificate->donation->donor_email)->queue(new CertificateIssuedMail($certificate)); $certificate->update(['emailed_at'=>now()]); } }
